import React, { useState } from "react";
import bankingImg from "../Accets/fin.jpeg";

export default function BankingApis() {
  const [openFAQ, setOpenFAQ] = useState(null);

  const faqs = [
    {
      question: "What are Banking APIs?",
      answer:
        "Banking APIs allow businesses to securely connect with banks for payments, account verification, balance checks and fund transfers.",
    },
    {
      question: "Are the APIs secure?",
      answer:
        "Yes. All APIs use OAuth authentication, encryption and comply with industry security standards.",
    },
    {
      question: "How quickly can I integrate?",
      answer:
        "Most businesses complete integration within a day using our SDKs and documentation.",
    },
  ];

  return (
    <div className="bg-black text-white">

      {/* Hero */}
      <section className="max-w-7xl mx-auto px-8 py-28 grid lg:grid-cols-2 gap-16 items-center">

        <div>
          <p className="uppercase tracking-widest text-orange-500 font-semibold">
            Banking APIs
          </p>

          <h1 className="text-6xl font-bold mt-6 leading-tight">
            Connect Directly With Banking Infrastructure
          </h1>

          <p className="text-gray-400 mt-8 text-lg leading-8">
            Access account verification, balance enquiry, fund transfers,
            payouts and banking services through powerful APIs.
          </p>

          <button className="mt-10 px-8 py-4 rounded-full bg-orange-500 text-black font-semibold hover:bg-orange-400 transition">
            Get API Access
          </button>
        </div>

        <div>
          <img
            src={bankingImg}
            alt="Banking APIs"
            className="rounded-3xl shadow-2xl"
          />
        </div>

      </section>

      {/* Features */}

      <section className="max-w-7xl mx-auto px-8 py-24">

        <div className="text-center mb-16">
          <h2 className="text-5xl font-bold">
            Why Choose Banking APIs?
          </h2>

          <p className="text-gray-400 mt-4">
            Enterprise-grade banking infrastructure for modern businesses.
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">

          {[
            {
              icon:"🏦",
              title:"Account Verification",
              desc:"Instant account validation before transfers."
            },
            {
              icon:"💸",
              title:"Fund Transfers",
              desc:"NEFT, IMPS and RTGS APIs."
            },
            {
              icon:"📊",
              title:"Balance Check",
              desc:"Real-time account information."
            },
            {
              icon:"⚡",
              title:"Fast Integration",
              desc:"REST APIs with developer SDKs."
            },
          ].map((item)=>(
            <div
              key={item.title}
              className="bg-gray-900 rounded-3xl border border-gray-800 p-8 hover:border-orange-500 transition"
            >
              <div className="text-5xl mb-5">{item.icon}</div>

              <h3 className="text-2xl font-semibold">
                {item.title}
              </h3>

              <p className="text-gray-400 mt-4">
                {item.desc}
              </p>

            </div>
          ))}

        </div>

      </section>

      {/* API Services */}

      <section className="max-w-7xl mx-auto px-8 py-24">

        <div className="text-center mb-16">
          <h2 className="text-5xl font-bold">
            Available APIs
          </h2>
        </div>

        <div className="grid md:grid-cols-3 gap-8">

          {[
            "Account Verification",
            "Balance Enquiry",
            "Payout APIs",
            "Fund Transfer",
            "Beneficiary Management",
            "Statement APIs",
          ].map((api)=>(
            <div
              key={api}
              className="bg-gray-900 rounded-2xl border border-gray-800 py-10 text-center hover:border-orange-500 transition"
            >
              <h3 className="text-2xl font-semibold">
                {api}
              </h3>
            </div>
          ))}

        </div>

      </section>

      {/* FAQ */}

      <section className="max-w-5xl mx-auto px-8 py-24">

        <h2 className="text-5xl font-bold text-center mb-14">
          Frequently Asked Questions
        </h2>

        {faqs.map((faq,index)=>(
          <div
            key={index}
            className="border-b border-gray-800 py-6 cursor-pointer"
            onClick={()=>setOpenFAQ(openFAQ===index ? null : index)}
          >

            <div className="flex justify-between">

              <h3 className="text-xl font-semibold">
                {faq.question}
              </h3>

              <span>
                {openFAQ===index ? "-" : "+"}
              </span>

            </div>

            {openFAQ===index && (
              <p className="mt-4 text-gray-400">
                {faq.answer}
              </p>
            )}

          </div>
        ))}

      </section>

      {/* CTA */}

      <section className="bg-orange-500 py-24">

        <div className="max-w-4xl mx-auto text-center">

          <h2 className="text-5xl font-bold text-black">
            Ready to Integrate?
          </h2>

          <p className="text-black/80 mt-6 text-xl">
            Connect your business to modern banking infrastructure today.
          </p>

          <button className="mt-10 bg-black text-white px-10 py-4 rounded-full">
            Contact Sales
          </button>

        </div>

      </section>

    </div>
  );
}