 import { useState } from "react";
import { Link } from "react-router-dom";

export default function ServicesMenu() {
  const [servicesOpen, setServicesOpen] = useState(false);

  return (
    <li
      className="relative group"
      onMouseEnter={() => setServicesOpen(true)}
      onMouseLeave={() => setServicesOpen(false)}
    >
      <span className="cursor-pointer flex items-center gap-1 text-lg font-semibold hover:text-orange-500 transition">
        <Link to="/services">Services</Link>
        <span className="text-sm">▾</span>
      </span>

      <div
  className={`absolute right-[-80px] mt-6 w-[900px] max-w-[95vw]
  
        bg-gradient-to-br from-gray-900 via-gray-900 to-black
        rounded-3xl shadow-2xl border border-gray-800
        transition-all duration-300 z-50
        ${
          servicesOpen
            ? "opacity-100 visible translate-y-0"
            : "opacity-0 invisible translate-y-6"
        }`}
      >
        <div className="grid grid-cols-2 gap-6 p-8">

          <Link
            to="/WebDevelopment"
            className="group p-5 rounded-2xl border border-gray-800 hover:border-orange-500 hover:bg-gray-800/40 transition"
          >
            <div className="text-3xl mb-3">💻</div>

            <h4 className="text-white font-semibold group-hover:text-orange-500">
              Web Development
            </h4>

            <p className="text-gray-400 text-sm mt-2">
              Modern websites and enterprise web applications.
            </p>
          </Link>

          <Link
            to="/MobileApp"
            className="group p-5 rounded-2xl border border-gray-800 hover:border-orange-500 hover:bg-gray-800/40 transition"
          >
            <div className="text-3xl mb-3">📱</div>

            <h4 className="text-white font-semibold group-hover:text-orange-500">
              Mobile Apps
            </h4>

            <p className="text-gray-400 text-sm mt-2">
              Native and cross-platform mobile applications.
            </p>
          </Link>

          <Link
            to="/UI"
            className="group p-5 rounded-2xl border border-gray-800 hover:border-orange-500 hover:bg-gray-800/40 transition"
          >
            <div className="text-3xl mb-3">🎨</div>

            <h4 className="text-white font-semibold group-hover:text-orange-500">
              UI / UX Design
            </h4>

            <p className="text-gray-400 text-sm mt-2">
              Beautiful and user-friendly digital experiences.
            </p>
          </Link>

          <Link
            to="/EnterpriseSolutions"
            className="group p-5 rounded-2xl border border-gray-800 hover:border-orange-500 hover:bg-gray-800/40 transition"
          >
            <div className="text-3xl mb-3">🏢</div>

            <h4 className="text-white font-semibold group-hover:text-orange-500">
              Enterprise Solutions
            </h4>

            <p className="text-gray-400 text-sm mt-2">
              Scalable digital solutions for growing businesses.
            </p>
          </Link>

        </div>

        <div className="border-t border-gray-800 px-10 py-5 flex justify-between items-center">
          <p className="text-gray-400 text-sm">
            End-to-end digital transformation services.
          </p>

          <Link
            to="/contact"
            className="px-7 py-2.5 rounded-full bg-orange-500 text-black font-semibold hover:bg-orange-400 transition"
          >
            Get Started
          </Link>
        </div>
      </div>
    </li>
  );
}