import React, { useState } from "react";
import { motion } from "framer-motion";
import {
  ArrowRight,
  CheckCircle2,
  ShieldCheck,
  Zap,
  TrendingUp,
  Users,
  Building2,
  Clock3,
  ChevronRight,
  PlayCircle,
  Star,
  Sparkles,
  BarChart3,
  Lock,
  Globe,
} from "lucide-react";

export default function SolutionPageTemplate({
  title,
  subtitle,
  image,
  challenges = [],
  solutions = [],
  features = [],
  benefits = [],
  industries = [],
  faqs = [],
}) {
  const [openFAQ, setOpenFAQ] = useState(0);

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.7,
      },
    },
  };

  return (
    <div className="bg-[#050505] text-white overflow-hidden">

      {/* Background Glow */}

      <div className="fixed inset-0 pointer-events-none">

        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[700px] h-[700px] rounded-full bg-orange-500/10 blur-[180px]" />

        <div className="absolute bottom-0 right-0 w-[500px] h-[500px] rounded-full bg-orange-400/5 blur-[160px]" />

        <div className="absolute top-1/2 left-0 w-[300px] h-[300px] rounded-full bg-orange-500/5 blur-[140px]" />

      </div>

      {/* ================= HERO ================= */}

      <section className="relative pt-36 pb-28 px-6">

        <div className="max-w-7xl mx-auto grid lg:grid-cols-2 gap-20 items-center">

          {/* LEFT */}

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
          >

            <div className="inline-flex items-center gap-2 border border-orange-500/30 bg-orange-500/10 px-5 py-2 rounded-full text-orange-400 text-sm font-medium">

              <Sparkles size={16} />

              Enterprise Digital Solutions

            </div>

            <h1 className="mt-8 text-5xl md:text-6xl lg:text-7xl font-bold leading-tight">

              {title}

            </h1>

            <p className="mt-8 text-gray-300 text-lg leading-9 max-w-xl">

              {subtitle}

            </p>

            {/* Buttons */}

            <div className="flex flex-wrap gap-5 mt-10">

              <button className="group bg-orange-500 hover:bg-orange-600 transition px-8 py-4 rounded-xl font-semibold flex items-center gap-3">

                Book Demo

                <ArrowRight
                  size={18}
                  className="group-hover:translate-x-1 transition"
                />

              </button>

              <button className="border border-white/10 hover:border-orange-500 hover:bg-orange-500/10 transition px-8 py-4 rounded-xl font-semibold flex items-center gap-3">

                <PlayCircle size={18} />

                Learn More

              </button>

            </div>

            {/* Trust */}

            <div className="grid grid-cols-3 gap-5 mt-16">

              <div className="bg-[#111111] border border-white/10 rounded-2xl p-5">

                <ShieldCheck className="text-orange-500 mb-3" />

                <h3 className="font-bold text-2xl">99.99%</h3>

                <p className="text-gray-400 text-sm mt-1">
                  Platform Uptime
                </p>

              </div>

              <div className="bg-[#111111] border border-white/10 rounded-2xl p-5">

                <TrendingUp className="text-orange-500 mb-3" />

                <h3 className="font-bold text-2xl">3X</h3>

                <p className="text-gray-400 text-sm mt-1">
                  Faster Processing
                </p>

              </div>

              <div className="bg-[#111111] border border-white/10 rounded-2xl p-5">

                <Users className="text-orange-500 mb-3" />

                <h3 className="font-bold text-2xl">500+</h3>

                <p className="text-gray-400 text-sm mt-1">

                  Businesses

                </p>

              </div>

            </div>

          </motion.div>

          {/* RIGHT */}

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="relative"
          >

            <div className="absolute inset-0 rounded-[40px] bg-orange-500 blur-[100px] opacity-20"></div>

            <img
              src={image}
              alt={title}
              className="relative rounded-[40px] border border-white/10 shadow-2xl"
            />

            {/* Floating Card */}

            <motion.div
              animate={{
                y: [0, -12, 0],
              }}
              transition={{
                repeat: Infinity,
                duration: 4,
              }}
              className="absolute -left-8 top-10 bg-[#101010]/90 backdrop-blur-xl border border-white/10 rounded-2xl p-5 shadow-2xl"
            >

              <div className="flex gap-4">

                <div className="w-12 h-12 rounded-xl bg-orange-500/10 flex items-center justify-center">

                  <BarChart3 className="text-orange-500" />

                </div>

                <div>

                  <h4 className="font-semibold">

                    Real-Time Analytics

                  </h4>

                  <p className="text-sm text-gray-400 mt-1">

                    Live transaction monitoring

                  </p>

                </div>

              </div>

            </motion.div>

            <motion.div
              animate={{
                y: [0, 12, 0],
              }}
              transition={{
                repeat: Infinity,
                duration: 5,
              }}
              className="absolute -right-8 bottom-10 bg-[#101010]/90 backdrop-blur-xl border border-white/10 rounded-2xl p-5 shadow-2xl"
            >

              <div className="flex gap-4">

                <div className="w-12 h-12 rounded-xl bg-orange-500/10 flex items-center justify-center">

                  <Lock className="text-orange-500" />

                </div>

                <div>

                  <h4 className="font-semibold">

                    Enterprise Security

                  </h4>

                  <p className="text-sm text-gray-400 mt-1">

                    PCI DSS compliant

                  </p>

                </div>

              </div>

            </motion.div>

          </motion.div>

        </div>

      </section>
            {/* ================= CHALLENGES ================= */}

      <section className="py-28 px-6 relative">
        <div className="max-w-7xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="text-center mb-16"
          >
            <span className="text-orange-500 font-semibold uppercase tracking-widest text-sm">
              Challenges
            </span>

            <h2 className="text-4xl lg:text-5xl font-bold mt-4">
              Industry Challenges
            </h2>

            <p className="text-gray-400 mt-6 max-w-2xl mx-auto text-lg">
              Businesses today require secure, scalable and intelligent
              financial infrastructure to remain competitive in the digital era.
            </p>
          </motion.div>

          <div className="grid md:grid-cols-2 xl:grid-cols-4 gap-8">

            {challenges.map((item, index) => (
              <motion.div
                key={index}
                variants={fadeUp}
                initial="hidden"
                whileInView="show"
                viewport={{ once: true }}
                transition={{ delay: index * .15 }}
                whileHover={{
                  y: -10,
                  transition: { duration: .25 }
                }}
                className="group relative overflow-hidden rounded-3xl border border-white/10 bg-[#111111] p-8"
              >

                <div className="absolute inset-0 bg-gradient-to-br from-orange-500/10 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition duration-500" />

                <div className="relative">

                  <div className="w-16 h-16 rounded-2xl bg-orange-500/10 flex items-center justify-center mb-8 group-hover:bg-orange-500 transition-all">

                    <ShieldCheck className="group-hover:text-white transition-all" />

                  </div>

                  <h3 className="text-2xl font-semibold mb-4">
                    {item.title}
                  </h3>

                  <p className="text-gray-400 leading-8">
                    {item.description}
                  </p>

                </div>

              </motion.div>
            ))}

          </div>

        </div>
      </section>

      {/* ================= WHY CHOOSE US ================= */}

      <section className="py-28 px-6 bg-[#090909]">

        <div className="max-w-7xl mx-auto grid lg:grid-cols-2 gap-20 items-center">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="relative"
          >

            <div className="absolute inset-0 bg-orange-500 blur-[120px] opacity-20 rounded-full"></div>

            <img
              src={image}
              alt={title}
              className="relative rounded-[32px] border border-white/10"
            />

          </motion.div>

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
          >

            <span className="text-orange-500 font-semibold uppercase tracking-widest">
              Why Choose Us
            </span>

            <h2 className="text-5xl font-bold mt-5 leading-tight">
              Built for Modern Digital Businesses
            </h2>

            <p className="text-gray-400 mt-8 text-lg leading-9">
              We empower businesses with enterprise-grade payment
              infrastructure, secure APIs, intelligent automation and scalable
              fintech solutions that accelerate growth.
            </p>

            <div className="space-y-6 mt-12">

              {[
                "Enterprise-grade security",
                "Real-time transaction monitoring",
                "Instant settlements",
                "Scalable cloud infrastructure",
                "Developer-friendly APIs",
                "24×7 dedicated support"
              ].map((point, index) => (

                <div
                  key={index}
                  className="flex items-center gap-4"
                >

                  <div className="w-11 h-11 rounded-full bg-orange-500 flex items-center justify-center">

                    <CheckCircle2 size={18} />

                  </div>

                  <p className="text-lg">
                    {point}
                  </p>

                </div>

              ))}

            </div>

          </motion.div>

        </div>

      </section>

      {/* ================= FEATURES ================= */}

      <section className="py-28 px-6">

        <div className="max-w-7xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="text-center mb-16"
          >

            <span className="text-orange-500 uppercase tracking-widest text-sm font-semibold">
              Capabilities
            </span>

            <h2 className="text-5xl font-bold mt-5">
              Core Features
            </h2>

            <p className="text-gray-400 mt-6 max-w-3xl mx-auto">
              Everything your business needs to simplify payments,
              automate financial operations and deliver exceptional customer
              experiences.
            </p>

          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">

            {features.map((feature, index) => (

              <motion.div
                key={index}
                variants={fadeUp}
                initial="hidden"
                whileInView="show"
                viewport={{ once: true }}
                transition={{ delay: index * .1 }}
                whileHover={{
                  y: -10
                }}
                className="group rounded-3xl border border-white/10 bg-[#101010] p-8 relative overflow-hidden"
              >

                <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition duration-500 bg-gradient-to-br from-orange-500/10 to-transparent" />

                <div className="relative">

                  <div className="w-16 h-16 rounded-2xl bg-orange-500/10 flex items-center justify-center mb-8">

                    <Zap className="text-orange-500" />

                  </div>

                  <h3 className="text-2xl font-semibold mb-4">
                    {feature.title}
                  </h3>

                  <p className="text-gray-400 leading-8">
                    {feature.description}
                  </p>

                  <button className="mt-8 flex items-center gap-2 text-orange-500 font-semibold group-hover:gap-4 transition-all">

                    Learn More

                    <ChevronRight size={18} />

                  </button>

                </div>

              </motion.div>

            ))}

          </div>

        </div>

      </section>

            {/* ================= BENEFITS ================= */}

      <section className="py-28 px-6 bg-[#090909]">
        <div className="max-w-7xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="text-center mb-16"
          >

            <span className="text-orange-500 uppercase tracking-widest font-semibold">
              Business Benefits
            </span>

            <h2 className="text-5xl font-bold mt-5">
              Why Businesses Trust Us
            </h2>

            <p className="text-gray-400 max-w-3xl mx-auto mt-6 text-lg">
              From startups to large enterprises, our infrastructure is built
              to maximize efficiency, security and business growth.
            </p>

          </motion.div>

          <div className="grid lg:grid-cols-4 md:grid-cols-2 gap-8 mb-16">

            <motion.div
              whileHover={{ y: -8 }}
              className="rounded-3xl bg-[#111111] border border-white/10 p-8"
            >
              <TrendingUp className="text-orange-500 mb-6" size={40}/>
              <h3 className="text-5xl font-bold">99.99%</h3>
              <p className="text-gray-400 mt-3">Platform Uptime</p>
            </motion.div>

            <motion.div
              whileHover={{ y: -8 }}
              className="rounded-3xl bg-[#111111] border border-white/10 p-8"
            >
              <Zap className="text-orange-500 mb-6" size={40}/>
              <h3 className="text-5xl font-bold">3X</h3>
              <p className="text-gray-400 mt-3">Faster Processing</p>
            </motion.div>

            <motion.div
              whileHover={{ y: -8 }}
              className="rounded-3xl bg-[#111111] border border-white/10 p-8"
            >
              <ShieldCheck className="text-orange-500 mb-6" size={40}/>
              <h3 className="text-5xl font-bold">100%</h3>
              <p className="text-gray-400 mt-3">Secure Infrastructure</p>
            </motion.div>

            <motion.div
              whileHover={{ y: -8 }}
              className="rounded-3xl bg-[#111111] border border-white/10 p-8"
            >
              <Clock3 className="text-orange-500 mb-6" size={40}/>
              <h3 className="text-5xl font-bold">24/7</h3>
              <p className="text-gray-400 mt-3">Expert Support</p>
            </motion.div>

          </div>

          <div className="grid lg:grid-cols-2 gap-8">

            {benefits.map((item,index)=>(
              <motion.div
                key={index}
                variants={fadeUp}
                initial="hidden"
                whileInView="show"
                viewport={{once:true}}
                whileHover={{x:8}}
                className="rounded-3xl bg-[#111111] border border-white/10 p-8 flex gap-6"
              >

                <div className="w-16 h-16 rounded-2xl bg-orange-500 flex items-center justify-center shrink-0">
                  <CheckCircle2/>
                </div>

                <div>
                  <h3 className="text-2xl font-semibold">
                    {item.title}
                  </h3>

                  <p className="text-gray-400 mt-4 leading-8">
                    {item.description}
                  </p>
                </div>

              </motion.div>
            ))}

          </div>

        </div>
      </section>

      {/* ================= HOW IT WORKS ================= */}

      <section className="py-28 px-6">

        <div className="max-w-6xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{once:true}}
            className="text-center mb-20"
          >

            <span className="text-orange-500 uppercase tracking-widest font-semibold">
              Process
            </span>

            <h2 className="text-5xl font-bold mt-5">
              How It Works
            </h2>

          </motion.div>

          <div className="relative">

            <div className="absolute left-6 top-0 bottom-0 w-[2px] bg-orange-500/30"></div>

            {[
              {
                title:"Consultation",
                desc:"Understand your business requirements and identify the ideal fintech solution."
              },
              {
                title:"Integration",
                desc:"Quick API integration with comprehensive technical documentation."
              },
              {
                title:"Testing",
                desc:"Validate security, performance and compliance before deployment."
              },
              {
                title:"Go Live",
                desc:"Launch confidently with monitoring, analytics and dedicated support."
              }

            ].map((step,index)=>(

              <motion.div
                key={index}
                variants={fadeUp}
                initial="hidden"
                whileInView="show"
                viewport={{once:true}}
                className="relative flex gap-8 mb-14"
              >

                <div className="w-12 h-12 rounded-full bg-orange-500 flex items-center justify-center font-bold shrink-0">
                  {index+1}
                </div>

                <div className="bg-[#111111] border border-white/10 rounded-3xl p-8 flex-1">

                  <h3 className="text-2xl font-semibold">
                    {step.title}
                  </h3>

                  <p className="text-gray-400 mt-4 leading-8">
                    {step.desc}
                  </p>

                </div>

              </motion.div>

            ))}

          </div>

        </div>

      </section>

      {/* ================= INDUSTRIES ================= */}

      <section className="py-28 px-6 bg-[#090909]">

        <div className="max-w-7xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{once:true}}
            className="text-center mb-16"
          >

            <span className="text-orange-500 uppercase tracking-widest font-semibold">
              Industries
            </span>

            <h2 className="text-5xl font-bold mt-5">
              Businesses We Empower
            </h2>

          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">

            {industries.map((item,index)=>(

              <motion.div
                key={index}
                whileHover={{
                  y:-8,
                  scale:1.03
                }}
                className="rounded-3xl bg-[#111111] border border-white/10 p-8 text-center"
              >

                <Building2
                  size={42}
                  className="mx-auto text-orange-500 mb-6"
                />

                <h3 className="text-2xl font-semibold">
                  {item}
                </h3>

              </motion.div>

            ))}

          </div>

        </div>

      </section>

            {/* ================= FAQ ================= */}

      <section className="py-28 px-6">

        <div className="max-w-5xl mx-auto">

          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="show"
            viewport={{ once: true }}
            className="text-center mb-16"
          >

            <span className="text-orange-500 uppercase tracking-widest font-semibold">
              FAQs
            </span>

            <h2 className="text-5xl font-bold mt-5">
              Frequently Asked Questions
            </h2>

            <p className="text-gray-400 mt-6">
              Everything you need to know before getting started.
            </p>

          </motion.div>

          <div className="space-y-5">

            {faqs.map((faq, index) => (

              <motion.div
                key={index}
                layout
                className="rounded-3xl border border-white/10 bg-[#111111] overflow-hidden"
              >

                <button
                  onClick={() =>
                    setOpenFAQ(openFAQ === index ? -1 : index)
                  }
                  className="w-full flex justify-between items-center p-7 text-left"
                >

                  <span className="text-xl font-semibold">
                    {faq.question}
                  </span>

                  <ChevronRight
                    className={`transition-transform ${
                      openFAQ === index ? "rotate-90" : ""
                    }`}
                  />

                </button>

                {openFAQ === index && (

                  <motion.div
                    initial={{ opacity: 0, height: 0 }}
                    animate={{
                      opacity: 1,
                      height: "auto",
                    }}
                    exit={{
                      opacity: 0,
                      height: 0,
                    }}
                    className="px-7 pb-7"
                  >

                    <p className="text-gray-400 leading-8">
                      {faq.answer}
                    </p>

                  </motion.div>

                )}

              </motion.div>

            ))}

          </div>

        </div>

      </section>

      {/* ================= CTA ================= */}

      <section className="pb-32 px-6">

        <motion.div
          variants={fadeUp}
          initial="hidden"
          whileInView="show"
          viewport={{ once: true }}
          className="max-w-7xl mx-auto rounded-[40px] overflow-hidden relative"
        >

          <div className="absolute inset-0 bg-gradient-to-r from-orange-500 via-orange-600 to-orange-500" />

          <div className="absolute top-0 left-0 w-80 h-80 rounded-full bg-white/10 blur-[120px]" />

          <div className="relative px-12 py-20 lg:px-20 flex flex-col lg:flex-row justify-between items-center gap-12">

            <div>

              <span className="inline-flex items-center gap-2 bg-white/10 px-4 py-2 rounded-full text-sm">

                <Star size={16} />

                Let's Build Together

              </span>

              <h2 className="text-4xl lg:text-6xl font-bold mt-6 leading-tight">

                Ready to Transform

                <br />

                Your Business?

              </h2>

              <p className="mt-6 text-orange-100 text-lg max-w-2xl leading-8">

                Empower your organization with secure APIs,
                enterprise-grade payment infrastructure,
                automation tools and intelligent fintech solutions.

              </p>

            </div>

            <div className="flex flex-col sm:flex-row gap-5">

              <button className="bg-black hover:bg-[#111] transition px-8 py-4 rounded-xl font-semibold flex items-center gap-3">

                Book a Demo

                <ArrowRight size={18} />

              </button>

              <button className="border border-white/30 hover:bg-white hover:text-black transition px-8 py-4 rounded-xl font-semibold">

                Contact Sales

              </button>

            </div>

          </div>

        </motion.div>

      </section>

    </div>
  );
}