import React from "react";
import verificationImg from "../Accets/fin.jpeg";

export default function VerificationSuite() {
  return (
    <div className="bg-black text-white">

      {/* Hero */}
      <section className="max-w-7xl mx-auto px-8 py-28 grid lg:grid-cols-2 gap-16 items-center">

        <div>
          <p className="uppercase tracking-widest text-orange-500 font-semibold">
            Verification Suite
          </p>

          <h1 className="text-6xl font-bold mt-6 leading-tight">
            Secure Identity Verification at Scale
          </h1>

          <p className="text-gray-400 mt-8 text-lg leading-8">
            Perform instant KYC, PAN, Aadhaar, GST and bank verification with
            enterprise-grade accuracy and speed.
          </p>

          <button className="mt-10 px-8 py-4 rounded-full bg-orange-500 text-black font-semibold hover:bg-orange-400 transition">
            Start Verification
          </button>
        </div>

        <div>
          <img
            src={verificationImg}
            alt="Verification Suite"
            className="rounded-3xl shadow-2xl"
          />
        </div>

      </section>

      {/* Features */}
      <section className="max-w-7xl mx-auto px-8 py-24">

        <div className="text-center mb-16">
          <h2 className="text-5xl font-bold">Why Verification Suite?</h2>
          <p className="text-gray-400 mt-4">
            Fast, compliant and scalable identity verification system.
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">

          {[
            { icon: "🆔", title: "KYC Verification", desc: "Instant user onboarding checks." },
            { icon: "📄", title: "PAN Validation", desc: "Verify PAN details in real-time." },
            { icon: "🏦", title: "Bank Verification", desc: "Check account authenticity." },
            { icon: "⚡", title: "Fast API", desc: "Lightning fast response times." },
          ].map((item) => (
            <div
              key={item.title}
              className="bg-gray-900 rounded-3xl border border-gray-800 p-8 hover:border-orange-500 transition"
            >
              <div className="text-5xl mb-5">{item.icon}</div>
              <h3 className="text-2xl font-semibold">{item.title}</h3>
              <p className="text-gray-400 mt-4">{item.desc}</p>
            </div>
          ))}

        </div>

      </section>

    </div>
  );
}
