import { useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function Contact() {
  const formRef = useRef();
  const [showPopup, setShowPopup] = useState(false);

  const handleSubmit = async (e) => {
  e.preventDefault();

  console.log("1. Submit clicked");
  

  const formData = {
    name: e.target.user_name.value,
    email: e.target.user_email.value,
    message: e.target.message.value,
  };

  console.log("2. Form Data:", formData);

  try {
    console.log("3. Sending request...");

    const res = await fetch("http://127.0.0.1:5000/api/contact", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(formData),
    });

    console.log("4. Response received:", res.status);

    const data = await res.json();

    console.log("Response:", data);

    console.log("5. Data:", data);

  } catch (error) {
    console.log("ERROR:", error);
    alert("Server error ❌");
  }
};

  const fadeUp = {
    hidden: { opacity: 0, y: 50 },
    show: { opacity: 1, y: 0 },
  };

  const stagger = {
    hidden: {},
    show: { transition: { staggerChildren: 0.15 } },
  };

  const hoverGlow = {
    hover: {
      scale: 1.03,
      boxShadow: "0px 20px 30px rgba(255,165,0,0.4)",
    },
  };

  return (
    <div className="bg-gray-950 min-h-screen text-gray-100 relative">

      {/* POPUP */}
      <AnimatePresence>
        {showPopup && (
          <motion.div
            initial={{ y: -50, opacity: 0 }}
            animate={{ y: 20, opacity: 1 }}
            exit={{ y: -50, opacity: 0 }}
            transition={{ type: "spring", stiffness: 500, damping: 30 }}
            className="fixed top-0 left-1/2 -translate-x-1/2 bg-orange-500 text-black font-semibold px-6 py-4 rounded-b-xl shadow-lg z-50"
          >
            🎉 Your message has been sent!
          </motion.div>
        )}
      </AnimatePresence>

      {/* HERO */}
      <section className="relative h-[400px] flex items-center justify-center text-center bg-cover bg-center"
        style={{
          backgroundImage:
            "url('https://images.pexels.com/photos/3184291/pexels-photo-3184291.jpeg?auto=compress&cs=tinysrgb&w=1600')",
        }}
      >
        <motion.div className="absolute inset-0 bg-black/60" />

        <motion.div className="relative z-10 max-w-2xl px-6">
          <h1 className="text-4xl md:text-5xl font-extrabold text-white mb-4">
            Contact <span className="text-orange-500">Uni</span>bComp
          </h1>
          <p className="text-gray-300 text-lg mb-6">
            Have a question or want to collaborate?
          </p>
        </motion.div>
      </section>

      {/* FORM */}
      <section className="py-24 max-w-3xl mx-auto px-6">
        <div className="bg-gray-800 rounded-3xl p-10 shadow-lg">

          <h2 className="text-3xl font-bold text-orange-600 mb-6">
            Send Us a Message
          </h2>

          <form onSubmit={handleSubmit} className="space-y-6">

            <input
              type="text"
              name="user_name"
              placeholder="Your Name"
              className="w-full p-4 text-black rounded-xl"
              required
            />

            <input
              type="email"
              name="user_email"
              placeholder="Your Email"
              className="w-full p-4 text-black rounded-xl"
              required
            />

            <textarea
              name="message"
              placeholder="Your Message"
              rows="6"
              className="w-full p-4 text-black rounded-xl"
              required
            ></textarea>

            <button
              type="submit"
              className="w-full bg-orange-600 text-black font-semibold py-4 rounded-full hover:bg-orange-500 transition"
            >
              Send Message
            </button>

          </form>
        </div>
      </section>
    </div>
  );
}