import { useState } from "react";
import { Link } from "react-router-dom";

export default function SolutionsMenu() {
  const [solutionsOpen, setSolutionsOpen] = useState(false);

  const solutions = [
    {
      title: "E-Commerce",
      icon: "🛒",
      description: "Online payments, seller onboarding & customer verification.",
      path: "/solutions/ecommerce",
    },
    {
      title: "Logistics",
      icon: "🚚",
      description: "Fleet payments, COD settlement & driver verification.",
      path: "/solutions/logistics",
    },
    {
      title: "Healthcare",
      icon: "🏥",
      description: "Patient verification, claims & healthcare payments.",
      path: "/solutions/healthcare",
    },
    {
      title: "Marketplace",
      icon: "🛍️",
      description: "Vendor onboarding, KYC & commission management.",
      path: "/solutions/marketplace",
    },
  ];

  return (
    <li
      className="relative"
      onMouseEnter={() => setSolutionsOpen(true)}
      onMouseLeave={() => setSolutionsOpen(false)}
    >
      <span className="cursor-pointer flex items-center gap-1 text-lg font-semibold hover:text-orange-500 transition">
        <Link to="/solutions">Solutions</Link>
        <span className="text-sm">▾</span>
      </span>

      <div
        className={`absolute left-1/2 -translate-x-1/2 mt-6 w-[900px]
        bg-gradient-to-br from-gray-900 via-gray-900 to-black
        rounded-3xl shadow-2xl border border-gray-800
        transition-all duration-300 z-50
        ${
          solutionsOpen
            ? "opacity-100 visible translate-y-0"
            : "opacity-0 invisible translate-y-6"
        }`}
      >
        <div className="grid grid-cols-2 gap-6 p-8">

          {solutions.map((item) => (
            <Link
              key={item.title}
              to={item.path}
              className="group p-6 rounded-2xl border border-gray-800 hover:border-orange-500 hover:bg-gray-800/40 transition"
            >
              <div className="text-4xl mb-4">{item.icon}</div>

              <h4 className="text-white font-semibold text-xl group-hover:text-orange-500">
                {item.title}
              </h4>

              <p className="text-gray-400 mt-3">
                {item.description}
              </p>
            </Link>
          ))}

        </div>
      </div>
    </li>
  );
}