import { Link } from "react-router-dom";
import {
  ShoppingCart,
  Truck,
  HeartPulse,
  Store,
  ArrowRight,
} from "lucide-react";

const solutions = [
  {
    title: "E-Commerce",
    description:
      "Empower online businesses with secure payments, seller onboarding, and customer verification.",
    icon: <ShoppingCart size={40} className="text-orange-500" />,
    path: "/solutions/ecommerce",
  },
  {
    title: "Logistics",
    description:
      "Simplify fleet operations with driver verification, COD settlements, and instant payouts.",
    icon: <Truck size={40} className="text-orange-500" />,
    path: "/solutions/logistics",
  },
  {
    title: "Healthcare",
    description:
      "Digitize healthcare with secure payments, patient verification, and claims processing.",
    icon: <HeartPulse size={40} className="text-orange-500" />,
    path: "/solutions/healthcare",
  },
  {
    title: "Marketplace",
    description:
      "Manage sellers, automate KYC, handle commissions, and streamline vendor payouts.",
    icon: <Store size={40} className="text-orange-500" />,
    path: "/solutions/marketplace",
  },
];

export default function Solutions() {
  return (
    <div className="min-h-screen bg-[#0B0B0B] text-white pt-32 pb-20 px-6">
      <div className="max-w-7xl mx-auto">

        <div className="text-center mb-16">
          <span className="text-orange-500 uppercase tracking-widest font-semibold">
            Industry Solutions
          </span>

          <h1 className="text-5xl font-bold mt-4">
            Solutions Built For Every Industry
          </h1>

          <p className="text-gray-400 mt-6 max-w-2xl mx-auto text-lg">
            Discover scalable technology solutions designed to accelerate
            growth across modern businesses.
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-8">

          {solutions.map((solution, index) => (
            <Link
              key={index}
              to={solution.path}
              className="bg-[#151515] border border-gray-800 rounded-3xl p-8 hover:border-orange-500 hover:-translate-y-2 transition duration-300 group"
            >
              {solution.icon}

              <h2 className="text-2xl font-bold mt-6">
                {solution.title}
              </h2>

              <p className="text-gray-400 mt-4 leading-7">
                {solution.description}
              </p>

              <div className="flex items-center gap-2 mt-8 text-orange-500 font-semibold group-hover:gap-4 transition-all">
                Explore Solution
                <ArrowRight size={18} />
              </div>
            </Link>
          ))}

        </div>

      </div>
    </div>
  );
}