 import { Link } from "react-router-dom";

export default function MobileMenu({ isOpen, setIsOpen }) {
  return (
    <div
      className={`md:hidden overflow-hidden transition-all duration-500 ease-in-out ${
        isOpen
          ? "max-h-[600px] opacity-100"
          : "max-h-0 opacity-0"
      }`}
    >
      <ul className="bg-gray-900 border-t border-gray-800 px-6 py-6 space-y-4 text-gray-300">

        <li>
          <Link onClick={() => setIsOpen(false)} to="/">
            Home
          </Link>
        </li>

        <li>
          <Link onClick={() => setIsOpen(false)} to="/work">
            Work
          </Link>
        </li>

        <li>
          <Link onClick={() => setIsOpen(false)} to="/products">
            Products
          </Link>
        </li>

        <li>
          <Link onClick={() => setIsOpen(false)} to="/solutions">
            Solutions
          </Link>
        </li>

        <li>
          <Link onClick={() => setIsOpen(false)} to="/services">
            Services
          </Link>
        </li>

        <li>
          <Link onClick={() => setIsOpen(false)} to="/careers">
            Careers
          </Link>
        </li>

        <li>
          <Link
            onClick={() => setIsOpen(false)}
            to="/contact"
            className="block text-center bg-orange-600 text-black py-2 rounded-full"
          >
            Contact Us
          </Link>
        </li>

      </ul>
    </div>
  );
}