import { useState } from "react";
import { Link } from "react-router-dom";
import Logo from "../Accets/logo.png";

import ProductsMenu from "./Navbar/ProductsMenu";
import SolutionsMenu from "./Navbar/SolutionsMenu";
import ServicesMenu from "./Navbar/ServicesMenu";
import MobileMenu from "./Navbar/MobileMenu";

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="fixed top-0 left-0 w-full z-50 backdrop-blur-2xl border-b border-gray-800 bg-black/70">
      <div className="max-w-7xl mx-auto px-6 py-5 flex justify-between items-center">

        {/* Logo */}
        <Link to="/">
          <img src={Logo} alt="Logo" className="h-10 w-auto" />
        </Link>

        {/* Desktop Menu */}
        <ul className="hidden md:flex items-center gap-10 text-gray-300">

          <li>
            <Link
              to="/"
              className="hover:text-orange-500 transition"
            >
              Home
            </Link>
          </li>

          <li>
            <Link
              to="/work"
              className="hover:text-orange-500 transition"
            >
              Work
            </Link>
          </li>

          <ProductsMenu />

          <SolutionsMenu />

          <ServicesMenu />

          <li>
            <Link
              to="/careers"
              className="hover:text-orange-500 transition"
            >
              Careers
            </Link>
          </li>

          <li>
            <Link
              to="/contact"
              className="px-5 py-2.5 rounded-full bg-orange-600 text-black font-semibold hover:bg-orange-500 transition"
            >
              Contact Us
            </Link>
          </li>

        </ul>

        <button
          onClick={() => setIsOpen(!isOpen)}
          className="md:hidden text-white text-2xl"
        >
          {isOpen ? "✕" : "☰"}
        </button>

      </div>

      <MobileMenu
        isOpen={isOpen}
        setIsOpen={setIsOpen}
      />
    </nav>
  );
}